114: 	// Removed keys in Local
115: 	for (const key of baseToLocal.removed.values()) {
116: 		// Got updated in remote
117: 		if (baseToRemote.updated.has(key)) {
118: 			conflicts.add(key);
119: 		}
120: 	}
121: 
