169: 			continue;
170: 		}
171: 		// Got updated in remote
172: 		if (baseToRemote.updated.has(key)) {
173: 			// Has different value
174: 			if (localToRemote.updated.has(key)) {
175: 				conflicts.add(key);
176: 			}
177: 		}
178: 	}
179: 
180: 	// Updated keys in Remote
