309: function isSameKeybinding(a: IUserFriendlyKeybinding, b: IUserFriendlyKeybinding): boolean {
310: 	if (a.command !== b.command) {
311: 		return false;
312: 	}
313: 	if (a.key !== b.key) {
314: 		return false;
315: 	}
316: 	const whenA = ContextKeyExpr.deserialize(a.when);
317: 	const whenB = ContextKeyExpr.deserialize(b.when);
318: 	if ((whenA && !whenB) || (!whenA && whenB)) {
319: 		return false;
320: 	}
321: 	if (whenA && whenB && !whenA.equals(whenB)) {
322: 		return false;
323: 	}
324: 	if (!objects.equals(a.args, b.args)) {
325: 		return false;
326: 	}
327: 	return true;
